convertToWIASleep.pseudocode:
function convertPSGToWIASleep(psgReport) {
  return {
    recordId: generateUUID(),
    subjectId: psgReport.patient_id,
    timestamp: psgReport.study_date,
    dataSource: 'psg',
    scoringMethod: psgReport.scoring_criteria || 'AASM_2020',
    sleepArchitecture: {
      summary: {
        timeInBed_min: psgReport.TIB,
        sleepPeriod_min: psgReport.SPT,
        totalSleepTime_min: psgReport.TST,
        sleepEfficiency_pct: psgReport.SE,
        sleepOnsetLatency_min: psgReport.SOL,
        remLatency_min: psgReport.RL,
        wakeAfterSleepOnset_min: psgReport.WASO,
        awakenings: psgReport.awakening_count,
        arousals_per_hour: psgReport.ArI
      },
      stagePercentages: {
        n1_pct: psgReport.N1_pct,
        n2_pct: psgReport.N2_pct,
        n3_sws_pct: psgReport.N3_pct,
        rem_pct: psgReport.REM_pct
      },
      hypnogram: {
        epochDuration_sec: 30,
        startTime: psgReport.lights_off,
        stages: psgReport.epoch_stages
      }
    },
    sleepDisorders: {
      ahi_events_per_hour: psgReport.AHI,
      oxygenDesaturationIndex: psgReport.ODI,
      plm_index: psgReport.PLMI
    }
  };
}
